import{_ as t,a,b as o,c as d}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as n,o as r,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Přidání kanálu Yandex","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/yandex.md","filePath":"cs-CZ/upload/yandex.md","lastUpdated":1781962217000}'),s={name:"cs-CZ/upload/yandex.md"};function c(p,e,k,h,u,v){return r(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="pridani-kanalu-yandex" tabindex="-1">Přidání kanálu Yandex <a class="header-anchor" href="#pridani-kanalu-yandex" aria-label="Permalink to &quot;Přidání kanálu Yandex&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Proč je potřeba</th></tr></thead><tbody><tr><td>Účet Yandex</td><td>Pro přihlášení a autorizaci Yandex Disk</td></tr><tr><td>OAuth aplikace Yandex</td><td>Pro vytvoření <code>Client ID</code> a <code>Client Secret</code></td></tr><tr><td>Vaše doména ImgBed</td><td>Pro OAuth redirect URI</td></tr><tr><td>Dostupné místo v Yandex Disk</td><td>Skutečné úložiště pro soubory</td></tr></tbody></table><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><h3 id="krok-1-vytvorte-oauth-aplikaci-yandex" tabindex="-1">Krok 1: Vytvořte OAuth aplikaci Yandex <a class="header-anchor" href="#krok-1-vytvorte-oauth-aplikaci-yandex" aria-label="Permalink to &quot;Krok 1: Vytvořte OAuth aplikaci Yandex&quot;">​</a></h3><ol><li>Otevřete stránku pro vytvoření OAuth aplikace Yandex:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Pokud budete přesměrováni k přihlášení, nejdřív se přihlaste účtem Yandex.</li><li>Vytvořte novou aplikaci.</li><li>Dejte aplikaci srozumitelný název, například <code>imgbed-yandex</code>.</li><li>Najděte nastavení callback nebo redirect URL.</li><li>Zadejte:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="krok-2-potvrdte-opravneni" tabindex="-1">Krok 2: Potvrďte oprávnění <a class="header-anchor" href="#krok-2-potvrdte-opravneni" aria-label="Permalink to &quot;Krok 2: Potvrďte oprávnění&quot;">​</a></h3><p>Pro aktuální integraci Yandex v ImgBed ponechte pod <code>Yandex.Disk REST API</code> tato čtyři oprávnění:</p><table tabindex="0"><thead><tr><th>Oprávnění</th><th>Účel</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>Umožní ImgBed ukládat soubory do složky aplikace</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Čte soubory a odkazy ke stažení</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Nahrává soubory, vytváří složky a maže soubory</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Čte kapacitu disku a využité místo</td></tr></tbody></table><p>Pokud pod <code>Yandex ID API</code> vidíte i tato oprávnění, jsou volitelná:</p><table tabindex="0"><thead><tr><th>Text oprávnění</th><th>Doporučení</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Volitelné</td></tr><tr><td><code>Access to email address</code></td><td>Volitelné</td></tr></tbody></table><p>Nahrávání, stahování, mazání a kapacita závisejí hlavně na čtyřech oprávněních <code>Yandex.Disk REST API</code> výše.</p><p><img src="'+t+'" alt="Nastavení oprávnění Yandex Disk" loading="lazy"></p><h3 id="krok-3-zkopirujte-udaje-aplikace" tabindex="-1">Krok 3: Zkopírujte údaje aplikace <a class="header-anchor" href="#krok-3-zkopirujte-udaje-aplikace" aria-label="Permalink to &quot;Krok 3: Zkopírujte údaje aplikace&quot;">​</a></h3><p>Po vytvoření aplikace zkopírujte:</p><table tabindex="0"><thead><tr><th>Pole Yandex</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Zapsání Client ID a Secret" loading="lazy"></p><h3 id="krok-4-vyplnte-kanal-yandex" tabindex="-1">Krok 4: Vyplňte kanál Yandex <a class="header-anchor" href="#krok-4-vyplnte-kanal-yandex" aria-label="Permalink to &quot;Krok 4: Vyplňte kanál Yandex&quot;">​</a></h3><p>V Nastavení nahrávání vyberte <code>Yandex</code> a vyplňte:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co zadat</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> aplikace Yandex</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> aplikace Yandex</td></tr><tr><td>Refresh Token</td><td>Zatím nechte prázdné</td></tr><tr><td>Kořenový adresář</td><td>Volitelné. Výchozí je <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+o+'" alt="Úprava konfigurace kanálu" loading="lazy"></p><h3 id="krok-5-ziskejte-refresh-token" tabindex="-1">Krok 5: Získejte Refresh Token <a class="header-anchor" href="#krok-5-ziskejte-refresh-token" aria-label="Permalink to &quot;Krok 5: Získejte Refresh Token&quot;">​</a></h3><ol><li>V ImgBed klikněte na <code>Get Token</code>.</li><li>Přihlaste se k účtu Yandex, který chcete připojit.</li><li>Potvrďte autorizaci.</li><li>Callback stránka zobrazí <code>Refresh Token</code>.</li><li>Zkopírujte ho.</li><li>Vraťte se do ImgBed a vložte ho do pole <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="Kopírování Refresh Token po autorizaci" loading="lazy"></p><h3 id="krok-6-ulozte-kanal" tabindex="-1">Krok 6: Uložte kanál <a class="header-anchor" href="#krok-6-ulozte-kanal" aria-label="Permalink to &quot;Krok 6: Uložte kanál&quot;">​</a></h3><p>Po vyplnění všech polí kanál uložte.</p><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otevřete Yandex OAuth Console</span></span>
<span class="line"><span>-&gt; Vytvořte aplikaci</span></span>
<span class="line"><span>-&gt; Přidejte https://your-domain.com/api/oauth/yandex/callback</span></span>
<span class="line"><span>-&gt; Potvrďte oprávnění Yandex Disk</span></span>
<span class="line"><span>-&gt; Zkopírujte Client ID a Client Secret</span></span>
<span class="line"><span>-&gt; Zadejte Client ID / Client Secret do ImgBed</span></span>
<span class="line"><span>-&gt; Klikněte Get Token</span></span>
<span class="line"><span>-&gt; Zkopírujte Refresh Token z callback stránky</span></span>
<span class="line"><span>-&gt; Vložte ho zpět do ImgBed a uložte</span></span></code></pre></div><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ol><li>Registrace aplikace Yandex: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Získání authorization code přes URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const y=n(s,[["render",c]]);export{x as __pageData,y as default};
